+  void Mapper::Reset()
+  {
+    if (m_pSequentialScanMatcher)
+    {
+      delete m_pSequentialScanMatcher;
+      m_pSequentialScanMatcher = NULL;
+    }
+    if (m_pGraph)
+    {
+      delete m_pGraph;
+      m_pGraph = NULL;
+    }
+    if (m_pMapperSensorManager)
+    {
+      delete m_pMapperSensorManager;
+      m_pMapperSensorManager = NULL;
+    }
+	  m_Initialized = false;
+  }
