+   */
+  void Mapper::RemoveListener(MapperListener* pListener)
+  {
+	  std::vector<MapperListener*>::iterator iter = std::find(m_Listeners.begin(), m_Listeners.end(), pListener);
+	  if (iter != m_Listeners.end())
+	  {
+		  m_Listeners.erase(iter);
+	  }
+  }
